        return true
    }
    if cur.Left == nil && cur.Right == nil {
        return false
    }
    if cur.Left != nil {
        count -= cur.Left.Val
        if traversal(cur.Left, count) {
            return true
        }
        count += cur.Left.Val
    }
    if cur.Right != nil {
        count -= cur.Right.Val
        if traversal(cur.Right, count) {
            return true
        }
        count += cur.Right.Val
    }
    return false
}

